create table if not exists public.language_words (
  id bigint generated by default as identity primary key,
  created_at timestamptz default now() not null,
  category text not null,
  category_order integer not null,
  category_position integer not null,
  global_position integer not null unique,
  english_word text not null,
  spanish_word text not null,
  catalan_word text not null,
  english_phrase text not null,
  spanish_phrase text not null,
  catalan_phrase text not null,
  published_to text not null default ''
);

create index if not exists language_words_category_order_idx on public.language_words (category_order, category_position);
create index if not exists language_words_category_idx on public.language_words (category);

alter table public.language_words enable row level security;

drop policy if exists language_words_select on public.language_words;
create policy language_words_select
  on public.language_words
  for select
  to anon
  using (true);

